definition.script:
pipeline {
    agent any

    environment {
        SWAGGER_UI_DIR = '/sources/demo-swagger-ui'
        REST_DOCS_DIR  = '/sources/demo-rest-docs'
        DOCS_OUT       = '/tmp/docs-build'
    }

    stages {
        stage('Checkout') {
            steps {
                echo "原始碼已透過 Volume 掛載於 ${SWAGGER_UI_DIR} 與 ${REST_DOCS_DIR}"
                sh 'ls -la ${SWAGGER_UI_DIR}/pom.xml ${REST_DOCS_DIR}/pom.xml'
            }
        }

        stage('Build Swagger-UI') {
            steps {
                dir("${SWAGGER_UI_DIR}") {
                    sh 'mvn clean package -DskipTests -B'
                }
            }
            post {
                success {
                    archiveArtifacts artifacts: 'target/*.jar', allowEmptyArchive: true
                }
            }
        }

        stage('Build REST-Docs + Generate Docs') {
            steps {
                dir("${REST_DOCS_DIR}") {
                    sh 'mvn clean package -B'
                }
            }
            post {
                success {
                    sh "rm -rf ${DOCS_OUT} && mkdir -p ${DOCS_OUT}"
                    sh "cp -r ${REST_DOCS_DIR}/target/generated-docs/* ${DOCS_OUT}/"
                    archiveArtifacts artifacts: 'target/*.jar', allowEmptyArchive: true
                    archiveArtifacts artifacts: 'target/generated-docs/**', allowEmptyArchive: true
                }
            }
        }

        stage('Verify Validation') {
            steps {
                echo "=== 驗證 Global Exception Handler 正確攔截髒資料 ==="
                sh '''
                curl -s -X POST http://swagger-api:8080/api/users \
                    -H "Content-Type: application/json" \
                    -d '{"username":"","email":"bad","birthday":"2099-12-31"}' \
                    | python3 -m json.tool 2>/dev/null || echo "API 尚未啟動，跳過驗證"
                '''
            }
        }
    }

    post {
        always {
            cleanWs()
        }
        success {
            echo "✅ Pipeline 執行成功！文件已產生。"
        }
        failure {
            echo "❌ Pipeline 執行失敗，請檢查日誌。"
        }
    }
}
